svg.script:
const data = [
  { 
    title: "مساحة إعلانية متاحة", 
    desc: 'تواصل مع إدارة "صوان" لحجز هذه المساحة', 
    dir: "rtl" 
  },
  { 
    title: "Advertising space available", 
    desc: "Contact Siwane management to reserve this space", 
    dir: "ltr" 
  }
];

const mainEl = document.getElementById("text-main");
const subEl = document.getElementById("text-sub");

async function typeText(el, text, speed) {
  el.textContent = "";
  for (let char of text) {
    el.textContent += char;
    await new Promise(r => setTimeout(r, speed));
  }
}

async function startLoop() {
  let i = 0;
  while (true) {
    let item = data[i % 2];

    // ضبط الاتجاه لضمان الكتابة الصحيحة (يمين/يسار)
    mainEl.setAttribute("direction", item.dir);
    subEl.setAttribute("direction", item.dir);

    await typeText(mainEl, item.title, 100);
    await typeText(subEl, item.desc, 50);

    await new Promise(r => setTimeout(r, 8000));

    mainEl.textContent = "";
    subEl.textContent = "";
    i++;
  }
}

startLoop();
